      gap: 16px;\n    }\n    .blog-related-card {\n        padding: 24px 20px;\n    }\n    .blog-cta {\n        padding: 60px 20px;\n    }\n.blog-hero-inner {\n    max-width: 1200px;\n    margin: 0 auto;\n    padding: 0 24px;\n    position: relative;\n    z-index: 2;\n    animation: slide-up 0.8s ease-out;\n}\n.blog-data-number--success {\n    color: var(--event-color, #22C55E);\n}\n.blog-data-label--spaced {\n    margin-top: 12px;\n}\n.dw-section {\n    padding: 100px 80px;\n}\n.dw-section--white {\n    background: #ffffff;\n}\n.dw-section--gray {\n    background: #F5F7FA;\n}\n.dw-section--dark {\n    background: linear-gradient(135deg, #000864 0%, #1e3a5f 100%);\n    color: #ffffff;\n}\n.dw-section--blue {\n    background: linear-gradient(135deg, #00AFF0 0%, #0ea5e9 50%, #0284c7 100%);\n    color: #ffffff;\n    position: relative;\n}\n.dw-section--blue::before {\n    content: \'\';\n    position: absolute;\n    top: 0;\n    left: 0;\n    right: 0;\n    bottom: 0;\n    background: radial-gradient(ellipse at 20% 30%, rgba(255,255,255,0.15) 0%, transparent 50%);\n    pointer-events: none;\n}\n    .dw-section {\n        padding: 60px 40px;\n    }\n    .dw-section {\n        padding: 48px 24px;\n    }\n\n.blog-category-badge { background: #00AFF0; }\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"AMRP: Why You Don\'t Need a Separate APS System: Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"AMRP: Why You Don\'t Need a Separate APS System: Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"AMRP: Why You Don\'t Need a Separate APS System: Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><section class="blog-hero" style="position: relative; overflow: hidden;">\n        <div class="dw-d-bg dw-d-bg--corner-tl" style="opacity: 0.06;"></div>\n        <div class="blog-hero-inner" style="position: relative; z-index: 2;">\n            <a href="/blog/" class="blog-back-link">\n                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>\n                Back to Insights\n            </a>\n            <div class="blog-category-badge">PRODUCTION PLANNING</div>\n            <h1>AMRP: Why You Don\'t Need a Separate APS System</h1>\n            <div class="blog-meta">\n                <span>8 min read</span>\n                <span class="blog-meta-dot"></span>\n                <span>February 2026</span>\n            </div>\n        </div>\n    </section><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"AMRP: Why You Don\'t Need a Separate APS System: Body"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"AMRP: Why You Don\'t Need a Separate APS System: Body: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"AMRP: Why You Don\'t Need a Separate APS System: Body: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><article class="blog-body">\n\n        <!-- Opening -->\n        <p class="fade-in">\n            You bought an ERP for your factory. You set up your Bill of Materials (BOM), configured your production workflows, and trained your team. Then you sit down with your planner to create the production schedule for next month. You tell the system: here are the customer orders, here are the delivery dates, now show me the production plan. The system calculates material requirements, checks inventory, generates purchase orders. Everything looks good on paper. Then your planner looks at the calendar and says: "This won\'t work. Our CNC line can\'t handle this volume. We\'re going to miss half these delivery dates."\n        </p>\n\n        <p class="fade-in">\n            That is when you discover the gap. Your ERP only does MRP — Material Requirements Planning. It assumes you have infinite production capacity. It tells you what materials you need and when, but not whether your production lines can actually execute the plan. The schedule looks perfect until you try to run it on real machines with real constraints. To add capacity planning, your vendor says, you need a separate APS system — Advanced Planning and Scheduling. That is another license, another vendor, another integration project. Most enterprise ERP systems work this way. It is the industry default.\n        </p>\n\n        <p class="fade-in">\n            DigiWin\'s AMRP (Advanced MRP) does not work this way. It builds capacity planning directly into the ERP — at no extra cost, no separate system, no integration complexity. Materials and capacity planned together, in one database, from day one.\n        </p>\n\n        <hr class="blog-divider fade-in">\n\n        <!-- Section: What Standard MRP Misses -->\n        <h2 class="fade-in">What Standard MRP Misses</h2>\n\n        <p class="fade-in">\n            Standard MRP calculates material requirements but assumes unlimited production capacity. It looks at your orders, explodes the BOMs, calculates gross requirements, nets against inventory, and generates planned orders for materials. This is useful — you know what to buy and when. But it tells you nothing about whether your production floor can actually make those goods on time.\n        </p>\n\n        <p class="fade-in">\n            The result is production plans that look correct on paper but are impossible to execute. Your bottleneck machines get overloaded. Some work centers sit idle while others are double-booked. Delivery dates slip because the system scheduled more work than a production line can physically handle. Your planners spend hours — sometimes entire days — manually adjusting the MRP output to fit real capacity constraints.\n        </p>\n\n        <p class="fade-in">\n            Consider a typical scenario. You have three customer orders all due in Week 10. MRP schedules them all for production in Week 9 to allow time for final testing and shipping. But Week 9 already has 120 hours of work scheduled on your CNC line, and the line only has 100 hours of available capacity (after accounting for maintenance downtime and shift constraints). MRP does not see this problem. It generates the plan anyway. Then your production manager crosses out half the work orders and reschedules them by hand, knowing that some deliveries will now be late.\n        </p>\n\n        <div class="blog-pullquote fade-in">\n            MRP assumes infinite capacity. Your production floor does not have infinite capacity. That gap is why your delivery dates keep slipping.\n        </div>\n\n        <hr class="blog-divider fade-in">\n\n        <!-- Section: What AMRP Does Differently -->\n        <h2 class="fade-in">What AMRP Does Differently</h2>\n\n        <p class="fade-in">\n            DigiWin\'s AMRP integrates material planning and capacity planning in one system. When you schedule a production order, AMRP checks both material availability and production line capacity — simultaneously, in real time, from the same database.\n        </p>\n\n        <p class="fade-in">\n            <strong>Key capabilities:</strong>\n        </p>\n\n        <ul class="fade-in">\n            <li><strong>Backward scheduling from delivery date:</strong> AMRP starts with the customer delivery date and schedules backward, checking at each step whether materials are available and whether the required production line has capacity. If a bottleneck appears, the system flags it immediately — not after your planner discovers it manually.</li>\n            <li><strong>Forward scheduling when backward fails:</strong> If backward scheduling is not feasible (materials will arrive late, or capacity is already committed), AMRP automatically switches to forward scheduling and calculates the earliest realistic delivery date. You know immediately whether you can meet the customer\'s timeline or need to negotiate.</li>\n            <li><strong>Considers already-committed capacity:</strong> AMRP tracks capacity at the work center level, accounting for already-scheduled production orders. When a new order arrives, the system knows which time slots are still available and which are already blocked. No double-booking.</li>\n            <li><strong>Assembly coordination for JIT material arrival:</strong> For complex assemblies with multiple sub-components, AMRP schedules material arrivals to minimize inventory holding time. Components arrive just in time for assembly, not weeks early.</li>\n            <li><strong>Resource priority settings:</strong> You can configure priority rankings for internal production lines versus OEM outsourcing partners. AMRP schedules internal capacity first, then overflows to external partners only when internal lines are fully loaded.</li>\n            <li><strong>Rush order recalculation:</strong> When a priority order arrives mid-month, AMRP recalculates remaining capacity across all existing orders and reschedules in seconds — not hours of manual replanning.</li>\n        </ul>\n\n        <p class="fade-in">\n            This is not a separate APS system layered on top of the ERP. It is built into the core planning engine. One system. One database. Materials and capacity planned together.\n        </p>\n\n        <div class="blog-data-card fade-in">\n            <div class="blog-data-card-content">\n                <div class="blog-data-inline">\n                    <div>\n                        <div class="blog-data-number">MRP</div>\n                        <div class="blog-data-label">Materials Only<br>(Assumes Infinite Capacity)</div>\n                    </div>\n                    <div style="font-size: 32px; color: rgba(255,255,255,0.75);" aria-hidden="true">→</div>\n                    <div>\n                        <div class="blog-data-number">AMRP</div>\n                        <div class="blog-data-label">Materials + Capacity<br>(Built into DigiWin ERP)</div>\n                    </div>\n                </div>\n                <div class="blog-data-label" style="margin-top: 24px; font-size: 15px; color: rgba(255,255,255,0.9);">No extra license. No separate system. No integration complexity.</div>\n            </div>\n        </div>\n\n        <hr class="blog-divider fade-in">\n\n        <!-- Section: The APS Tax -->\n        <h2 class="fade-in">The APS Tax: What Other Vendors Charge</h2>\n\n        <p class="fade-in">\n            Many enterprise ERP vendors require separate APS purchases for capacity-aware planning. These are not small add-ons. Enterprise APS systems can cost as much as the ERP itself — sometimes more, depending on the number of production lines and complexity of scheduling rules. You pay for the APS license, the implementation project, the integration middleware, and the ongoing maintenance of two separate systems that need to stay synchronized.\n        </p>\n\n        <p class="fade-in">\n            And even after you pay for it, you still have integration complexity. The ERP manages orders, inventory, and financials. The APS system manages scheduling. Data flows back and forth between the two. When a rush order arrives, you update the ERP, wait for the data to sync to APS, run the APS optimizer, then push the revised schedule back to the ERP. This takes time — often hours, sometimes longer if the integration has issues. Your planners spend significant effort managing the handoff between systems rather than focusing on production optimization.\n        </p>\n\n        <p class="fade-in">\n            AMRP eliminates this entirely. There is no separate APS license to buy. No integration project. No synchronization delays. Capacity planning is built into the ERP from day one, using the same database, the same user interface, the same workflow your team already knows. When a rush order arrives, you update one system — and the capacity recalculation happens immediately.\n        </p>\n\n        <hr class="blog-divider fade-in">\n\n        <!-- Section: Real-World Impact -->\n        <h2 class="fade-in">Real-World Impact: Rush Orders and Resource Priority</h2>\n\n        <p class="fade-in">\n            <strong>Rush orders:</strong> In most factories, a priority customer order arriving mid-month triggers a day of chaos. The planner pulls up the existing MRP schedule, prints it out, and manually marks which orders can be delayed to make room for the rush job. Then they recalculate material requirements, check with the warehouse, call the production supervisor to confirm feasibility, and finally update the system with the revised plan. This takes hours — and the plan is already outdated by the time it is entered, because other orders have progressed or materials have arrived in the meantime.\n        </p>\n\n        <p class="fade-in">\n            With AMRP, the planner enters the rush order, flags it as priority, and clicks "reschedule." The system recalculates capacity across all existing orders, identifies which work can be deferred without missing critical deadlines, and generates a new schedule that accommodates the rush order — in seconds. The revised schedule accounts for material availability, production line capacity, and delivery date commitments across every order in the system. AMRP can be run multiple times per day for dynamic rescheduling as conditions change. Your planners spend less time updating spreadsheets and more time managing exceptions.\n        </p>\n\n        <p class="fade-in">\n            <strong>Resource priority:</strong> Many factories use a combination of internal production lines and external OEM partners. You want to maximize utilization of your own equipment (you already paid for it), and only overflow to OEM partners when internal capacity is fully booked. But coordinating this manually is complex — you need to know the real-time load on every internal line, compare it against incoming orders, and decide which jobs to send external.\n        </p>\n\n        <p class="fade-in">\n            AMRP lets you configure resource priority rules. You rank your internal production lines first, then list OEM partners in order of preference. When AMRP schedules a production order, it checks internal capacity first. If internal lines have available slots, the work is scheduled there. If internal capacity is fully loaded, AMRP assigns the order to the highest-priority external partner with availability. The system enforces your strategy automatically, without manual intervention.\n        </p>\n\n        <div class="blog-pullquote fade-in">\n            Your production plan is only as good as the capacity behind it. If your ERP ignores capacity, your plan is fiction.\n        </div>\n\n        <hr class="blog-divider fade-in">\n\n        <!-- Section: What This Means for Your Factory -->\n        <h2 class="fade-in">What This Means for Your Factory</h2>\n\n        <p class="fade-in">\n            If you are running standard MRP, you already know the pain. Your planners manually adjust the MRP output every week — or every day — to fit real capacity constraints. Your delivery performance suffers because the system schedules work that cannot physically be completed on time. You have considered buying a separate APS system, but the cost and complexity have kept you from pulling the trigger.\n        </p>\n\n        <p class="fade-in">\n            AMRP changes the calculation. You get capacity planning without the APS tax. No separate license. No integration project. No data synchronization delays. Capacity planning is built into the ERP, using the same database your team already works with. The cost is zero (beyond the standard DigiWin T100 license you are already using). The implementation complexity is zero (it is already there). The value is immediate — production plans that account for real capacity constraints, delivery dates you can actually meet, and planners who spend less time manually correcting the system.\n        </p>\n\n        <p class="fade-in">\n            This is not a future feature. It is not a premium add-on. It is standard functionality in <a href="/products/erp/">DigiWin\'s manufacturing ERP</a>, available today, included in the base license. If you are planning production for a manufacturing operation with capacity constraints — and every real factory has capacity constraints — AMRP eliminates the gap between your plan and your reality.\n        </p>\n\n    </article>\n\n    <!-- FAQ Section -->\n    <section class="dw-section" style="padding: 60px 0; background: #f8fafc;">\n      <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n        <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px;">Frequently Asked Questions</h2>\n        <div style="display: flex; flex-direction: column; gap: 12px;">\n          <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n            <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What is AMRP?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n            <div style="padding: 0 20px 16px 20px; background: white;">\n              <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">AMRP stands for Advanced Material Requirements Planning. It is DigiWin\'s built-in capacity-aware scheduling engine that integrates material planning and production capacity planning in one system. Unlike standard MRP which only calculates material requirements and assumes infinite production capacity, AMRP checks both material availability and production line capacity simultaneously, in real time, from the same database — ensuring your production plans are actually executable.</p>\n            </div>\n          </details>\n          <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n            <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What is the difference between MRP and AMRP?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n            <div style="padding: 0 20px 16px 20px; background: white;">\n              <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Standard MRP calculates material requirements but assumes unlimited production capacity — it tells you what materials you need but not whether your production lines can actually execute the plan. AMRP adds capacity constraints, split-order handling, and both backward scheduling (from delivery date) and forward scheduling (when backward is not feasible). AMRP also considers already-committed capacity to prevent double-booking, coordinates assembly timing for JIT material arrival, and supports resource priority settings for internal vs. OEM production.</p>\n            </div>\n          </details>\n          <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n            <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">Do I need a separate APS system with DigiWin ERP?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n            <div style="padding: 0 20px 16px 20px; background: white;">\n              <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">No. DigiWin\'s AMRP builds capacity planning directly into the ERP at no extra cost, with no separate system and no integration complexity. Most enterprise ERP vendors require a separate Advanced Planning and Scheduling (APS) system for capacity-aware planning, which can cost as much as the ERP itself. With DigiWin, materials and capacity are planned together in one database from day one — eliminating the APS license, the integration project, and the synchronization delays between separate systems.</p>\n            </div>\n          </details>\n          <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n            <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What are the 6 key AMRP capabilities?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n            <div style="padding: 0 20px 16px 20px; background: white;">\n              <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">The six key AMRP capabilities are: (1) Backward scheduling from delivery date with automatic bottleneck detection, (2) Forward scheduling when backward scheduling is not feasible to calculate the earliest realistic delivery date, (3) Already-committed capacity tracking at the work center level to prevent double-booking, (4) Assembly coordination for JIT material arrival to minimize inventory holding time, (5) Resource priority settings that schedule internal production lines first and overflow to OEM partners only when internal capacity is full, and (6) Rush order recalculation that reschedules remaining capacity across all existing orders in seconds.</p>\n            </div>\n          </details>\n        </div>\n      </div>\n    </section>\n\n    <!-- Related Articles --><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"AMRP: Why You Don\'t Need a Separate APS System: Related"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"AMRP: Why You Don\'t Need a Separate APS System: Related: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"AMRP: Why You Don\'t Need a Separate APS System: Related: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><section class="blog-related" style="position: relative; overflow: hidden;">\n        <div class="dw-wave-circles" style="opacity: 0.04;"></div>\n        <div class="blog-related-inner" style="position: relative; z-index: 2;">\n            <h2 class="fade-in">Related Articles</h2>\n            <div class="blog-related-grid">\n                <a href="/blog/lrp-vs-mrp/" class="blog-related-card fade-in">\n                    <div class="blog-related-card-category">Production Planning</div>\n                    <h3>LRP vs MRP: Which Planning Method Fits Your Factory?</h3>\n                    <span class="blog-related-card-link">\n                        Read article\n                        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M5 12h14M12 5l7 7-7 7"/></svg>\n                    </span>\n                </a>\n                <a href="/blog/feature-codes/" class="blog-related-card fade-in">\n                    <div class="blog-related-card-category">Production Planning</div>\n                    <h3>Feature Codes: How to Plan Products That Change Per Customer</h3>\n                    <span class="blog-related-card-link">\n                        Read article\n                        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M5 12h14M12 5l7 7-7 7"/></svg>\n                    </span>\n                </a>\n                <a href="/blog/shop-floor-scheduling/" class="blog-related-card fade-in">\n                    <div class="blog-related-card-category">Smart Factory</div>\n                    <h3>Shop Floor Mini-Scheduling: Real-Time Dispatch from AMRP to MES</h3>\n                    <span class="blog-related-card-link">\n                        Read article\n                        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M5 12h14M12 5l7 7-7 7"/></svg>\n                    </span>\n                </a>\n            </div>\n        </div>\n    </section>\n\n    <!-- CTA Section -->\n    <section class="blog-cta">\n        <div class="blog-cta-inner">\n            <h2 class="fade-in">Ready to Plan with Real Capacity?</h2>\n            <p class="fade-in">See how AMRP eliminates the gap between your production plan and your production reality.</p>\n            <a href="/demo/" class="blog-cta-btn fade-in">\n                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>\n                Let\'s Talk\n            </a>\n        </div>\n    </section><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100760;

